#include<bits/stdc++.h>using namespace std;int n,a[1000010],q,b[1000010];int check(int mid){	int sum=mid;	for(int i=1;i<=q;i++){		if(b[i]>0&&b[i]<a[mid]){			sum++;		}		if(b[i]<0&&abs(b[i])<=a[mid]){			sum--; 		}	}	return sum>=1;}int main(){	cin>>n>>q;	for(int i=1;i<=n;i++)cin>>a[i];	for(int i=1;i<=q;i++)cin>>b[i];	int sum=0;	for(int i=1;i<=q;i++){		if(b[i]<0){			sum++;		}	}	if(q-sum+n<=sum){		cout<<0;		return 0; 	}	int l=1,r=n,mid,z=0;	while(l<=r){		mid=(l+r)/2;		if(check(mid)){			r=mid-1;			z=mid;		}		else{			l=mid+1;		} 	}	cout<<z;    return 0;}